@Slf4j
@Tag("deployment")
public class JpgSnipeDatumCCLTest {

    private static final ObjectMapper OBJECT_MAPPER = new ObjectMapper();

    private static final String SETTINGS_SCRIPT_BYTES = "";

    private static final String POLICY_SNIPE_SCRIPT_BYTES = "";

    private static final Network NETWORK = Networks.mainnet();

    private static final String MNEMONIC = System.getenv("WALLET_MNEMONIC");

    private static final String BLOCKFROST_KEY = System.getenv("BLOCKFROST_KEY");

    static {
        log.info("WALLET_MNEMONIC: {}", MNEMONIC);
        log.info("BLOCKFROST_KEY: {}", BLOCKFROST_KEY);
    }

    private static final Account sniperAccount = Account.createFromMnemonic(NETWORK, MNEMONIC, 2, 0);

    private static final BFBackendService bfBackendService = new BFBackendService(Constants.BLOCKFROST_MAINNET_URL, BLOCKFROST_KEY);

    private static HybridUtxoSupplier hybridUtxoSupplier;

    private static QuickTxBuilder quickTxBuilder;

    private final AddressService addressService = new AddressServiceImpl(Constants.BLOCKFROST_MAINNET_URL, BLOCKFROST_KEY);

    private final TransactionService transactionService = new TransactionServiceImpl(Constants.BLOCKFROST_MAINNET_URL, BLOCKFROST_KEY);

    private final ListingDatumParser listingDatumParser = new ListingDatumParser(OBJECT_MAPPER);

    private final ListingDatumService listingDatumService = new ListingDatumService(transactionService, OBJECT_MAPPER);


    @BeforeAll
    public static void beforeAll() {

        hybridUtxoSupplier = new HybridUtxoSupplier(bfBackendService.getUtxoService());

        var protocolParamsSupplier = new DefaultProtocolParamsSupplier(bfBackendService.getEpochService());

        var scriptSupplier = new DefaultScriptSupplier(bfBackendService.getScriptService());

        var transactionEvaluator = new AikenTransactionEvaluator(hybridUtxoSupplier, protocolParamsSupplier, scriptSupplier);

        var transactionProcessor = new TransactionProcessor() {
            @Override
            public Result<String> submitTransaction(byte[] cborData) throws ApiException {
                return null;
            }

            @Override
            public Result<List<EvaluationResult>> evaluateTx(byte[] cbor, Set<Utxo> inputUtxos) throws ApiException {
                return transactionEvaluator.evaluateTx(cbor, inputUtxos);
            }
        };

        quickTxBuilder = new QuickTxBuilder(hybridUtxoSupplier,
                protocolParamsSupplier,
                scriptSupplier,
                transactionProcessor);
    }


    @Test
    public void mintSnipeTest() throws Exception {

        log.info("sniperAccount: {}", sniperAccount.baseAddress());

        var collectionPolicyId = "a5bb0e5bb275a573d744a021f9b3bff73595468e002755b447e01559";

        var treasuryAddress = new Account();
        log.info("treasuryAddress: {}", treasuryAddress.baseAddress());

        var sniperCustomerAccount = new Account();
        log.info("sniperCustomerAccount: {}", sniperCustomerAccount.baseAddress());

//        var snipeCustomerOnchainAddress = new Address(sniperCustomerAccount.getBaseAddress().getPaymentCredential().get(),
//                sniperCustomerAccount.getBaseAddress().getDelegationCredential().get());

        var snipeCustomerAddress = sniperCustomerAccount.getBaseAddress();

        var snipeCustomerOnchainAddressOpt = BlueprintUtil.toOnchainAddress(snipeCustomerAddress);
        if (snipeCustomerOnchainAddressOpt.isEmpty()) {
            Assertions.fail();
        }
        var snipeCustomerOnchainAddress = snipeCustomerOnchainAddressOpt.get();

        var bootstrapHash = HashUtil.getRandomHash();

        var settingParameters = ListPlutusData.of(
                ConstrPlutusData.of(0,
                        BytesPlutusData.of(HexUtil.decodeHexString(bootstrapHash)),
                        BigIntPlutusData.of(0)
                ));

        var settingsContract = PlutusBlueprintUtil.getPlutusScriptFromCompiledCode(
                AikenScriptUtil.applyParamToScript(settingParameters, SETTINGS_SCRIPT_BYTES),
                PlutusVersion.v3
        );

        var settingsAddress = AddressProvider.getEntAddress(settingsContract, NETWORK);

        var policySnipeParameters = ListPlutusData.of(BytesPlutusData.of(settingsContract.getScriptHash()));

        var policySnipeContract = PlutusBlueprintUtil.getPlutusScriptFromCompiledCode(
                AikenScriptUtil.applyParamToScript(policySnipeParameters, POLICY_SNIPE_SCRIPT_BYTES),
                PlutusVersion.v3
        );

        var policySnipeAddress = AddressProvider.getBaseAddress(Credential.fromScript(policySnipeContract.getScriptHash()),
                treasuryAddress.getBaseAddress().getDelegationCredential().get(),
                NETWORK);

        var treasuryOpt = BlueprintUtil.toOnchainAddress(treasuryAddress.getBaseAddress());
        if (treasuryOpt.isEmpty()) {
            Assertions.fail();
        }
        var treasury = treasuryOpt.get();

        var settings = new SettingsDatumData();
        settings.setOperatorFeePct(BigInteger.ONE);
        settings.setProtocolFeePct(BigInteger.ONE);
        settings.setMinOperatorFee(BigInteger.valueOf(1_000_000L));
        settings.setMinProtocolFee(BigInteger.valueOf(1_000_000L));
        settings.setProtocolTreasury(treasury);
        settings.setStakeCredential(PaymentCredential.verificationKey(treasuryAddress.getBaseAddress().getDelegationCredentialHash().get()));
        settings.setTxFeeBudget(BigInteger.valueOf(1_000_000L));
        settings.setAdminPkh(VerificationKeyHash.of(treasuryAddress.getBaseAddress().getPaymentCredentialHash().get()));

        var settingsAssetType = AssetType.fromUnit(settingsContract.getPolicyId() + HexUtil.encodeHexString("settings".getBytes()));
        var settingsNFT = Amount.asset(settingsAssetType.toUnit(), BigInteger.ONE);

        var settingsUtxo = Utxo.builder()
                .txHash(HashUtil.getRandomHash())
                .outputIndex(0)
                .amount(List.of(Amount.ada(10L), settingsNFT))
                .address(settingsAddress.getAddress())
                .inlineDatum(settings.toPlutusData().serializeToHex())
                .build();

        hybridUtxoSupplier.add(settingsUtxo);

        var policySnipe = new PolicySnipeDatumData();
        policySnipe.setOwnerPkh(new VerificationKeyHash(sniperCustomerAccount.getBaseAddress().getPaymentCredentialHash().get()));
        policySnipe.setNftDestination(snipeCustomerOnchainAddress);
        policySnipe.setPolicyId(new PolicyId(HexUtil.decodeHexString(collectionPolicyId)));
        policySnipe.setMaxPrice(BigInteger.valueOf(10_000_000L));
        policySnipe.setProtocolFee(BigInteger.valueOf(1_000_000L));


        var lockedAmount = Value.fromCoin(BigInteger.valueOf(13_000_000L))
                .add(Value.from(policySnipeContract.getPolicyId(), "0x", BigInteger.ONE));

        var sniperCustomerUtxo = Utxo.builder()
                .txHash(HashUtil.getRandomHash())
                .outputIndex(0)
                .amount(List.of(Amount.ada(100L)))
                .address(sniperCustomerAccount.baseAddress())
                .build();

        hybridUtxoSupplier.add(sniperCustomerUtxo);

        var tx = new Tx()
                .collectFrom(List.of(sniperCustomerUtxo))
                .mintAsset(policySnipeContract, Asset.builder().value(BigInteger.ONE).build(), ConstrPlutusData.of(0))
                .payToContract(policySnipeAddress.getAddress(), ValueUtil.toAmountList(lockedAmount), policySnipe.toPlutusData())
                .readFrom(settingsUtxo)
                .withChangeAddress(sniperCustomerAccount.baseAddress());

        var transaction = quickTxBuilder.compose(tx)
                .feePayer(sniperCustomerAccount.baseAddress())
                .build();

        log.info("transaction: {}", transaction.serializeToHex());

        log.info("transaction: {}", OBJECT_MAPPER.writeValueAsString(transaction));

        var sniperUtxoResult = bfBackendService.getUtxoService().getUtxos(sniperAccount.baseAddress(), 100, 1);

        if (!sniperUtxoResult.isSuccessful()) {
            Assertions.fail();
        }

        var snipeUtxo = Utxo.builder()
                .txHash(HashUtil.getRandomHash())
                .outputIndex(0)
                .amount(ValueUtil.toAmountList(lockedAmount))
                .address(policySnipeAddress.getAddress())
                .inlineDatum(policySnipe.toPlutusData().serializeToHex())
                .build();

        hybridUtxoSupplier.add(snipeUtxo);

        var assetType = AssetType.fromUnit("a5bb0e5bb275a573d744a021f9b3bff73595468e002755b447e01559484f534b594361736847726162303030323936393139");

        var addressUtxo = addressService
                .getAddressUtxosGivenAsset(JPG_CONTRACT_ADDRESS_V2, assetType.toUnit(), 1, 1, OrderEnum.asc)
                .getFirst();
        log.info("addressUtxo: {}", addressUtxo);

        var utxo = bfBackendService.getUtxoService().getTxOutput(addressUtxo.getTxHash(), addressUtxo.getOutputIndex()).getValue();

        var listingDatumOpt = listingDatumService.findPlutusData(addressUtxo.getTxHash(), addressUtxo.getDataHash());
        if (listingDatumOpt.isEmpty()) {
            Assertions.fail();
        }

        var listingDatum = listingDatumOpt.get();
        log.info("listingDatum: {}", listingDatum.serializeToHex());

        var listingDetailsOpt = listingDatumParser.parseDatumV2(listingDatum.serializeToHex());

        if (listingDetailsOpt.isEmpty()) {
            Assertions.fail();
        }

        var listingDetails = listingDetailsOpt.get();
        log.info("listingDetails: {}", listingDetails);

        var totalAmount = listingDetails.payees().stream().map(PaymentDetails::amount).reduce(Value::add).orElse(Value.builder().build()).getCoin();
        var expectedJpgStoreNftFees = Rational.from(totalAmount).multiply(Rational.from(20L, 980L)).floor();
        log.info("expectedJpgStoreNftFees: {}", expectedJpgStoreNftFees);

        var actualJpgStoreFees = BigInteger.valueOf(1_000_000L).max(expectedJpgStoreNftFees);
        log.info("actualJpgStoreFees: {}", actualJpgStoreFees);

        var txFeeDatum = getJpgUtxoHash(addressUtxo.getTxHash(), addressUtxo.getOutputIndex());

        var snipeTx = new Tx()
                // Collect SNIPE
                .collectFrom(snipeUtxo, ConstrPlutusData.of(0))
                // Collect NFT
                .collectFrom(utxo, ConstrPlutusData.of(0, BigIntPlutusData.of(0)), listingDatum)
                // BURN Snipe NFT
                .mintAsset(policySnipeContract, Asset.builder().value(BigInteger.ONE.negate()).build(), ConstrPlutusData.of(0))
                // Pay JPG Store Fees
                .payToContract("addr1xxzvcf02fs5e282qk3pmjkau2emtcsj5wrukxak3np90n2evjel5h55fgjcxgchp830r7h2l5msrlpt8262r3nvr8eksg6pw3p", Amount.lovelace(actualJpgStoreFees), txFeeDatum);

        // JPG Payees
        listingDetails.payees()
                .forEach(paymentDetails -> snipeTx.payToAddress(paymentDetails.beneficiary(), ValueUtil.toAmountList(paymentDetails.amount())));


        var snipeTag = getUtxoHash(snipeUtxo.getTxHash(), snipeUtxo.getOutputIndex());
        log.info("snipeTag: {}", snipeTag.serializeToHex());

        snipeTx
                // Deliver NFT
                .payToContract(sniperCustomerAccount.baseAddress(), Amount.asset(assetType.toUnit(), BigInteger.ONE), snipeTag)
                // Pay Sniper Protocol
                .payToContract(treasuryAddress.baseAddress(), Amount.ada(1L), snipeTag)
                .readFrom(settingsUtxo)
                // JPG Contract
                .readFrom("1693c508b6132e89b932754d657d28b24068ff5ff1715fec36c010d4d6470b3d", 0)
                .withChangeAddress(sniperAccount.baseAddress());

        var snipeTransaction = quickTxBuilder.compose(snipeTx)
                .feePayer(sniperAccount.baseAddress())
                .mergeOutputs(false)
                .build();

        log.info("snipeTransaction: {}", snipeTransaction.serializeToHex());

        log.info("snipeTransaction: {}", OBJECT_MAPPER.writeValueAsString(snipeTransaction));


    }

    public PlutusData getJpgUtxoHash(String txHash, int outputIndex) {
        var outRefHash = ConstrPlutusData.of(0,
                ConstrPlutusData.of(0, BytesPlutusData.of(HexUtil.decodeHexString(txHash))),
                BigIntPlutusData.of(outputIndex)
        );
        return BytesPlutusData.of(outRefHash.getDatumHashAsBytes());
    }

    public PlutusData getUtxoHash(String txHash, int outputIndex) {
        var outRefHash = ConstrPlutusData.of(0,
                BytesPlutusData.of(HexUtil.decodeHexString(txHash)),
                BigIntPlutusData.of(outputIndex)
        );
        return BytesPlutusData.of(outRefHash.getDatumHashAsBytes());
    }

}
